// 从当前文档提取样式信息
var doc = Application.ActiveDocument;
var stylesInfo = {};
var totalParagraphs = doc.Paragraphs.Count;

for (var i = 1; i <= totalParagraphs; i++) {
    var para = doc.Paragraphs(i);
    var text = para.Range.Text.trim();
    if (text.length === 0) continue;

    var styleKey = [
        para.Range.Font.Name,
        para.Range.Font.Size,
        para.Range.Font.Bold ? 'bold' : 'normal',
        para.Alignment
    ].join('|');

    if (!stylesInfo[styleKey]) {
        stylesInfo[styleKey] = {
            count: 0,
            samples: [],
            fontName: para.Range.Font.Name,
            fontSize: para.Range.Font.Size,
            bold: para.Range.Font.Bold,
            alignment: para.Alignment
        };
    }

    stylesInfo[styleKey].count++;
    if (stylesInfo[styleKey].samples.length < 2) {
        stylesInfo[styleKey].samples.push(text.substring(0, 50));
    }
}

var result = "✅ 样式模板提取完成！\n\n📄 源文档：" + doc.Name + "\n📊 共 " + Object.keys(stylesInfo).length + " 种样式，" + totalParagraphs + " 个段落\n\n## 提取的样式详情\n\n";

var alignmentMap = {
    0: "左对齐",
    1: "居中",
    2: "右对齐",
    3: "两端对齐"
};

var index = 1;
for (var key in stylesInfo) {
    var info = stylesInfo[key];
    result += "### 样式 " + (index++) + "（" + info.count + "处）\n";
    result += "字体: " + info.fontName + " | 字号: " + info.fontSize + "pt";
    if (info.bold) result += " | 加粗";
    result += " | 对齐: " + alignmentMap[info.alignment] + "\n\n";
}

return result;

